const bin=$input.item.binary||{};
const b=bin.data; if(!b) throw new Error('no pdf');
const docs=[{type:'document',source:{type:'base64',media_type:'application/pdf',data:b.data}}];
const truck='ФС1234', trailer='ВТ5678';
const prompt='Ти обробляєш комерційні документи на морський вантаж. ВИКОРИСТОВУЙ ДАНІ ВИКЛЮЧНО з Bill of Lading (коносамент) та Commercial Invoice (інвойс). Решту ІГНОРУЙ. Поверни СТРОГО валідний JSON без markdown: {"container":"","sender":"","receiver":"","port":"порт прибуття (Port of Discharge)","weight":"вага БРУТТО (Gross Weight) з одиницею","invoice":""}. Вага — брутто.';
const body={model:'claude-sonnet-4-6',max_tokens:1024,messages:[{role:'user',content:docs.concat([{type:'text',text:prompt}])}]};
return [{json:{body,truck,trailer}}];

const resp=$input.item.json;
let text=(resp.content&&Array.isArray(resp.content))?resp.content.map(c=>c.text||'').join(''):(resp.text||'');
text=text.replace(/```json/gi,'').replace(/```/g,'').trim();
let data={};try{data=JSON.parse(text);}catch(e){const m=text.match(/\{[\s\S]*\}/);if(m)data=JSON.parse(m[0]);}
const p=$('prep').item.json;
const container=(data.container||'').toString().trim();
const receiver=(data.receiver||'').toString().trim();
return [{json:{container,sender:(data.sender||'').trim(),receiver,port:(data.port||'').trim(),weight:(data.weight||'').trim(),invoice:(data.invoice||'').trim(),truck:p.truck,trailer:p.trailer,docTitle:'CMR draft №'+container+' '+receiver.split(/[,\n]/)[0].trim()}}];
